// ══════════════════════════════════════════════════
// 🏪 SHOPEE FLASH SALE MONITOR — Mini Version
// Copy paste ke Console DevTools (F12) halaman produk
// ══════════════════════════════════════════════════

(async function(){
  const f=n=>n.toLocaleString('id-ID');
  let c=0,s=Date.now(),p=-1,r=0;
  console.log('%c🏪 SHOPEE MONITOR AKTIF — Mantau Rp.1...','color:#00e5ff;font-weight:bold;font-size:13px');
  console.log('  Ketik stop() untuk berhenti\n');
  function getPrice(){
    const el=document.querySelector('[data-testid="product-price"],[class*="price"],span._3eX');
    if(el){
      const t=el.textContent.trim(),m=t.replace(/\./g,'').match(/(\d+)/);
      if(m) return{p:parseInt(m[1]),t};
    }
    return null;
  }
  function notify(){
    try{new AudioContext().createOscillator().start();}catch(e){}
    const d=document.createElement('div');
    d.style.cssText='position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(255,0,50,0.9);color:#fff;font-size:48px;font-weight:bold;display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:999999;cursor:pointer;text-align:center;font-family:Arial';
    d.innerHTML='<div style="font-size:80px">💥💥💥</div><div>🔥 RP.1 DETECTED!</div><div style="font-size:24px;margin:20px 0">KLIK CHECKOUT SEKARANG!</div><div style="font-size:16px;opacity:.7">Klik untuk tutup</div>';
    d.onclick=()=>d.remove();
    document.body.appendChild(d);
    setTimeout(()=>{
      document.querySelectorAll('button').forEach(b=>{
        if(b.textContent.toLowerCase().includes('beli')) b.click();
      });
    },500);
    console.log('%c\n💥💥 RP.1 DETECTED! CEKOUT SEKARANG! 💥💥\n','color:#ff3355;font-size:18px;font-weight:bold');
  }
  function loop(){
    c++;
    const x=getPrice();
    if(x&&x.p!==p){
      const tm=new Date().toLocaleTimeString();
      console.log(`[${tm}] ${x.t}${x.p<=1000?' 🔥':''}`);
      p=x.p;
    }
    if(x&&x.p<=1000&&!r){r=1;notify();return;}
    if(!r) setTimeout(loop,1000);
  }
  loop();
  window.stop=()=>{r=1;console.log('⏹️ Stopped')};
  window.stats=()=>console.log(`${c}x checks, ${((Date.now()-s)/60000).toFixed(1)}m`);
})();
